export class Estates_model {
  constructor() {
    this.state = {
      loading: true,
      estate_elements: [],
      estate_elements_empty: null,
      estate_main_text: {
        id: null,
        text: "",
      },
    };

    this.listeners = [];
  }

  setState = (newState) => {
    this.state = { ...this.state, ...newState };
    this.notifyListeners();
    console.log(this.state);
    return this.state;
  };

  registerListener = (listener) => {
    this.listeners = [...this.listeners, listener];

    listener(this.state);
  };

  notifyListeners = () => {
    this.listeners.forEach((listener) => {
      listener(this.state);
    });
  };

  fetch_estate_elements = () => {
    if (process.env.NODE_ENV === "production") {
      fetch("https://abbeyroad.org.uk/api/estates-page/fetch_page_elements")
        .then((res) => {
          return res.json();
        })
        .then((res) => {
          // successful fetch from estate_page tables
          if (
            res.success &&
            res.estate_page &&
            typeof res.estate_page === "object" &&
            Array.isArray(res.estate_page.estate_page_images) &&
            Array.isArray(res.estate_page.estate_page_elements)
          ) {
            const estatePage = res.estate_page;

            // 1️⃣ Group estate_page_elements by estate_title
            const elementsMap = {};
            let mainTextObj = null;

            estatePage.estate_page_elements.forEach((element) => {
              // Capture main text object
              if (element.estate_id === "estates-main-article1-p1") {
                mainTextObj = {
                  id: element.estate_id,
                  estate_main_text: element.estate_main_text,
                };
              }

              // Group into a map first
              if (element.estate_title) {
                if (!elementsMap[element.estate_title]) {
                  elementsMap[element.estate_title] = [];
                }
                elementsMap[element.estate_title].push(element);
              }
            });

            // Convert to array of groups
            let groupedElements = Object.entries(elementsMap).map(
              ([title, items]) => ({
                estate_title: title,
                elements: items,
              }),
            );

            // 2️⃣ Group estate_page_images by estate_category
            const imagesMap = {};
            estatePage.estate_page_images.forEach((image) => {
              const category = image.estate_category;
              if (category) {
                if (!imagesMap[category]) {
                  imagesMap[category] = [];
                }
                imagesMap[category].push(image);
              }
            });

            // 3️⃣ Merge images into groupedElements if estate_title matches estate_category
            groupedElements = groupedElements.map((group) => {
              const images = imagesMap[group.estate_title] || [];
              return {
                ...group,
                images, // new property containing matching images
              };
            });

            console.log("succesfful fetch");

            this.setState({
              loading: false,
              estate_elements: groupedElements,
              estate_elements_empty: null,
              estate_main_text: {
                id: mainTextObj.id,
                text: mainTextObj.estate_main_text,
              },
            });
          }
          // unsuccessful fetch from estate_page tables OR empty tables
          else {
            // successful fetch but empty tables
            if (res.success && res.estate_page === null) {
              this.setState({
                loading: false,
                estate_elements: [],
                estate_elements_empty: true,
                estate_main_text: {
                  id: null,
                  text: "",
                },
              });
            }
            // unsuccessful fetch from estate_page
            else {
              this.setState({
                loading: false,
                estate_elements: [],
                estate_elements_empty: null,
                estate_main_text: {
                  id: null,
                  text: "",
                },
              });
            }
          }
        })
        .catch((err) => {
          console.log(err);
        });
    } else {
      fetch("http://localhost:3001/api/estates-page/fetch_page_elements")
        .then((res) => {
          return res.json();
        })
        .then((res) => {
          // successful fetch from estate_page tables
          if (
            res.success &&
            res.estate_page &&
            typeof res.estate_page === "object" &&
            Array.isArray(res.estate_page.estate_page_images) &&
            Array.isArray(res.estate_page.estate_page_elements)
          ) {
            const estatePage = res.estate_page;

            console.log(estatePage);

            // 1️⃣ Group estate_page_elements by estate_title
            const elementsMap = {};
            let mainTextObj = null;

            estatePage.estate_page_elements.forEach((element) => {
              // Capture main text object
              if (element.estate_id === "estates-main-article1-p1") {
                mainTextObj = {
                  id: element.estate_id,
                  estate_main_text: element.estate_main_text,
                };
              }
              console.log(mainTextObj);

              // Group into a map first
              if (element.estate_title) {
                if (!elementsMap[element.estate_title]) {
                  elementsMap[element.estate_title] = [];
                }
                elementsMap[element.estate_title].push(element);
              }
            });

            // Convert to array of groups
            let groupedElements = Object.entries(elementsMap).map(
              ([title, items]) => ({
                estate_title: title,
                elements: items,
              }),
            );

            // 2️⃣ Group estate_page_images by estate_category
            const imagesMap = {};
            estatePage.estate_page_images.forEach((image) => {
              const category = image.estate_category;
              if (category) {
                if (!imagesMap[category]) {
                  imagesMap[category] = [];
                }
                imagesMap[category].push(image);
              }
            });

            // 3️⃣ Merge images into groupedElements if estate_title matches estate_category
            groupedElements = groupedElements.map((group) => {
              const images = imagesMap[group.estate_title] || [];
              return {
                ...group,
                images, // new property containing matching images
              };
            });

            this.setState({
              loading: false,
              estate_elements: groupedElements,
              estate_elements_empty: null,
              estate_main_text: {
                id: mainTextObj.id,
                text: mainTextObj.estate_main_text,
              },
            });
          }
          // unsuccessful fetch from estate_page tables OR empty tables
          else {
            // successful fetch but empty tables
            if (res.success && res.estate_page === null) {
              this.setState({
                loading: false,
                estate_elements: [],
                estate_elements_empty: true,
                estate_main_text: {
                  id: null,
                  text: "",
                },
              });
            }
            // unsuccessful fetch from estate_page
            else {
              this.setState({
                loading: false,
                estate_elements: [],
                estate_elements_empty: null,
                estate_main_text: {
                  id: null,
                  text: "",
                },
              });
            }
          }
        })
        .catch((err) => {
          console.log(err);
        });
    }
  };
}
