import { Estates_model } from "../model/model.js";
import { Estates_view } from "../view/view.js";

export class Estates_controller {
  constructor() {
    this.model = new Estates_model();
    this.view = new Estates_view();

    this.model.registerListener((state) => {
      this.view.render_page_elements(state);
    });

    this.model.fetch_estate_elements();
  }
}
